INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('aboriginal-57f41407-moex-00482', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-110-01c5eaab', 'sub-aboriginal-57f41407-05', NULL, 'single_choice', '詩文中常見以動物的狀態來比喻自己的處境或心情，下列詩文中的動物，具有這種作用的選項是：', '["羈鳥戀舊林，池魚思故淵。開荒南野際，守拙歸園田", "千山鳥飛絕，萬徑人蹤滅。孤舟簑笠翁，獨釣寒江雪", "山光悅鳥性，潭影空人心。萬籟此俱寂，惟聞鐘磬音", "眾鳥高飛盡，孤雲獨去閒。相看兩不厭，只有敬亭山"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:17+00:00", "source_pdf_sha1": "e5bf3f0d4288", "answer_pdf_sha1": "38e0530a220d", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00483', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-110-01c5eaab', 'sub-aboriginal-57f41407-05', NULL, 'single_choice', '白居易〈長恨歌〉：「黃埃散漫風蕭索，雲棧縈紆登劍閣。峨嵋山下少人行，旌旗無光日色薄。蜀江水 碧蜀山青，聖主朝朝暮暮情。行宮見月傷心色，夜雨聞鈴腸斷聲。」 下列敘述何者正確？', '["透過「黃埃散漫風蕭索」，表現出戰場上戰鬥激烈，黃沙滾滾", "透過「峨嵋山下少人行」，表現局面緊張，人民多躲避在山中", "蜀地的山水依舊清麗，那裡曾充滿明皇與貴妃昔日美好的回憶", "無論是在行宮看到月色，或是夜雨聽到鈴聲都讓明皇悲痛欲絕"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:17+00:00", "source_pdf_sha1": "e5bf3f0d4288", "answer_pdf_sha1": "38e0530a220d", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00484', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-110-01c5eaab', 'sub-aboriginal-57f41407-05', NULL, 'single_choice', '青青子佩，悠悠我思。縱我不往，子寧不來？（《詩經‧鄭風‧子衿》） 下列選項，何者不符合本詩所傳達的情感？', '["憶君心似西江水，日夜東流無歇時", "相思一夜梅花發，忽到窗前疑是君", "花紅易衰似郎意，水流無限似儂愁", "勸君更進一杯酒，西出陽關無故人"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:17+00:00", "source_pdf_sha1": "e5bf3f0d4288", "answer_pdf_sha1": "38e0530a220d", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00485', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-110-01c5eaab', 'sub-aboriginal-57f41407-05', NULL, 'single_choice', '涉江採芙蓉，蘭澤多芳草。採之欲遺誰，所思在遠道。還顧望舊鄉，長路漫浩浩。同心而離居，憂傷 以終老。（佚名〈涉江採芙蓉〉）這首詩所表現的情感是：', '["悲憤不已", "感傷思念", "歡喜自得", "感時憂國"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:17+00:00", "source_pdf_sha1": "e5bf3f0d4288", "answer_pdf_sha1": "38e0530a220d", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00486', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-110-01c5eaab', 'sub-aboriginal-57f41407-05', NULL, 'single_choice', '「舞蹈家羅曼菲學成歸國後，原本要去上班，但她突然想到：『如果我每天朝九晚五上班，就無法再上 那堂舞者必須上的課，我沒有辦法清楚地講那堂課是什麼？但是那堂課是每一個舞者的維他命，透過 這堂課，我感覺自己的精力，氣在走，我的精神狀態和身體狀態合而為一，我能掌握自己，跟自己擁 抱。因此，碰到現實上的挫折和悲傷，好像都不重要了。』」根據上文，下列敘述何者正確？', '["羅曼菲不當上班族，是因為厭煩朝九晚五的工作", "為了能掌握自己，跟自己擁抱，要去補習班上課", "吃維他命，可以讓舞者的精神狀態和身體狀態合而為一", "只要能持續當一位舞者，現實中的挫折和悲傷，都可以放下"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:17+00:00", "source_pdf_sha1": "e5bf3f0d4288", "answer_pdf_sha1": "38e0530a220d", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00487', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-110-01c5eaab', 'sub-aboriginal-57f41407-05', NULL, 'single_choice', '「我試著將人對『情感』的接收，放入生活的脈絡裡討論，化約成一個簡單的條件，在孩子成長過程 中，父母、教師與教育工作者，和孩子之間的應對，創造出內心情感連結的條件，若是具有關鍵性的 影響，是否可以作為教育工作中主要的脈絡？從人的感受：憤怒、難過、害怕、緊張、高興、快樂…… 一直到讓人深層內在感受的價值、意義、自由、接納與愛，去啟動人內在最重要的生命力，呵護與養 成人的生命能量。」 根據上文，作者強調教育孩子最主要的脈絡是：', '["生活作息", "生命能量", "價值判斷", "情意感受"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:17+00:00", "source_pdf_sha1": "e5bf3f0d4288", "answer_pdf_sha1": "38e0530a220d", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00488', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-110-01c5eaab', 'sub-aboriginal-57f41407-05', NULL, 'single_choice', '「我知道有一日我的花冠也將凋落，／而我並不感到心驚。／因為花朵的美麗只是樹身的一部，／生 命的成長，蓬勃與凋萎，／一如星月依循著自然的軌道前行，／遠勝過花朵的歡欣的——／是我能成 為更大的樹，／蔭庇更多的行人，／承載更多的歌聲，／冬日來到——／我便褪下了枝葉，／無聲地 安息／而我驕傲於／我是一棵獨立的樹——／不是藤蘿。」 下列選項，何者符合上述文句所欲表達之主旨？', '["人事無常，無須執著", "自主意識，不求依附", "真摯情感，難以改變", "滄海桑田，轉眼成空"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:17+00:00", "source_pdf_sha1": "e5bf3f0d4288", "answer_pdf_sha1": "38e0530a220d", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00489', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-110-01c5eaab', 'sub-aboriginal-57f41407-05', NULL, 'single_choice', '承上題，為何花朵凋落，文中的「我」卻不覺心驚？', '["安時處順，和光同塵", "花開花落，自然遞嬗", "春華秋實，必有收穫", "繁華落盡，終將幻滅"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:17+00:00", "source_pdf_sha1": "e5bf3f0d4288", "answer_pdf_sha1": "38e0530a220d", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00490', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-110-01c5eaab', 'sub-aboriginal-57f41407-05', NULL, 'single_choice', '「從沒聽說誰家的蟑螂咬傷了嬰兒的事情。日常潛入鳥籠鴿舍，也只撿點掉下來的糧食，絕不傷害鳥 兒。故我稱之為□，誰曰不宜！」 依文意推敲，上文□中最適合填入的選項是：', '["仁", "義", "禮", "智"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:17+00:00", "source_pdf_sha1": "e5bf3f0d4288", "answer_pdf_sha1": "38e0530a220d", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00491', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-110-01c5eaab', 'sub-aboriginal-57f41407-05', NULL, 'single_choice', '「六十五歲至一百歲都叫老，細分卻有霜紅之葉與枯木的差別；即使處於同一年齡層，一個充滿活力 視退休為第二個人生的開始，遂積極規劃、學習、籌備，展現出探險隊員一般的遠征樂趣，與一個自 覺日漸衰老、鑽入蝸牛老殼自怨自艾的人相比，其差異之大宛如星際。」這段話主要是要告訴我們：', '["我們要關心社會上有許多人過著自怨自艾的退休生活", "要有美好的退休生活，就要懂得欣賞霜紅之葉與枯木之美", "老人雖有年齡、體能狀態之分，但更關鍵的是自我的心態", "老人是社會的重要資產，人生經驗使他們有如探險隊員般的勇氣"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:17+00:00", "source_pdf_sha1": "e5bf3f0d4288", "answer_pdf_sha1": "38e0530a220d", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 41, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL)
